1174	// TestLand_IsNetworkFree verifies that Land() no longer performs remote fetch
1175	// or push work and that it releases the main-git lock as soon as it returns.
1176	func TestLand_IsNetworkFree(t *testing.T) {
1177		r := newLandTestRepo(t)
1178		ops := &localOnlyGitOps{}
1179	
1180		workerSHA := r.commitOn(r.baseSHA, "feature.txt", "feature\n", "feat: feature")
1181		req := LandRequest{
1182			WorktreeDir:  r.dir,
1183			BaseRev:      r.baseSHA,
1184			ResultRev:    workerSHA,
1185			BeadID:       "ddx-land-network-free",
1186			AttemptID:    "20260511T000000-network-free",
1187			TargetBranch: "main",
1188		}
1189		land, err := Land(r.dir, req, ops)
1190		if err != nil {
1191			t.Fatalf("Land: %v", err)
1192		}
1193		if land.Status != "landed" {
1194			t.Fatalf("expected status=landed, got %q (reason=%q)", land.Status, land.Reason)
1195		}
1196		if land.NewTip != workerSHA {
1197			t.Fatalf("expected new tip %s, got %s", workerSHA, land.NewTip)
1198		}
1199	
1200		acquired := make(chan time.Duration, 1)
1201		go func() {
1202			start := time.Now()
1203			if err := withMainGitLock(r.dir, func() error { return nil }); err != nil {
1204				t.Errorf("withMainGitLock after Land: %v", err)
1205				return
1206			}
1207			acquired <- time.Since(start)
1208		}()
1209	
1210		// Simulate caller-side post-Land work that should not hold the git lock.
1211		time.Sleep(5 * time.Second)
1212	
1213		select {
1214		case waited := <-acquired:
1215			if waited > time.Second {
1216				t.Fatalf("main-git lock was held for %s after Land returned; want < 1s", waited)
1217			}
1218		case <-time.After(time.Second):
1219			t.Fatal("timed out waiting for main-git lock acquisition after Land returned")
1220		}
1221	}
