96	// TestRecoverGitIndexLock_DeadOwner removes the lock when lsof identifies
97	// a pid that is not alive. This test requires lsof and is skipped if
98	// unavailable.
99	func TestRecoverGitIndexLock_DeadOwner(t *testing.T) {
100		if _, err := exec.LookPath("lsof"); err != nil {
101			t.Skip("lsof not available on PATH")
102		}
103	
104		dir := t.TempDir()
105		if err := os.Mkdir(filepath.Join(dir, ".git"), 0o755); err != nil {
106			t.Fatalf("setup .git: %v", err)
107		}
108		lockPath := filepath.Join(dir, ".git", "index.lock")
109	
110		// Spawn a short-lived process that opens the lock file, then exits.
111		cmd := exec.Command("sh", "-c", "exec 9>>"+lockPath+"; sleep 0.05")
112		if err := cmd.Start(); err != nil {
113			t.Fatalf("start helper: %v", err)
114		}
115		if err := cmd.Wait(); err != nil {
116			t.Fatalf("helper exited with error: %v", err)
117		}
118		// Helper is dead; age the lock past stale threshold so the unowned-stale branch removes it.
119		prev := gitlock.StaleAge
120		gitlock.StaleAge = 1 * time.Millisecond
121		t.Cleanup(func() { gitlock.StaleAge = prev })
122	
123		time.Sleep(5 * time.Millisecond)
124		result, err := recoverGitIndexLock(dir)
125		if err != nil {
126			t.Fatalf("recoverGitIndexLock: %v", err)
127		}
128		if !result.Removed {
129			t.Fatalf("expected removal, reason=%q owner=%d alive=%v",
130				result.Reason, result.OwnerPID, result.OwnerAlive)
131		}
132	}
